def list_topics(admin: KafkaAdminClient, args) -> int:
    consumer = admin._client
    consumer.poll(timeout_ms=args.timeout_ms)
    metadata = consumer.cluster
    topics = sorted(metadata.topics())
    print(json.dumps({
        "action": "list-topics",
        "topics": topics,
        "status": "ok",
    }))
    return 0


